output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?belligerent ?belligerentLabel ?leader ?leaderLabel WHERE {
  wd:Q16911838 wdt:P710 ?belligerent .
  ?belligerent wdt:P6 ?leader .
  OPTIONAL {
    ?belligerent rdfs:label ?belligerentLabel .
    FILTER(LANG(?belligerentLabel) = "en")
  }
  OPTIONAL {
    ?leader rdfs:label ?leaderLabel .
    FILTER(LANG(?leaderLabel) = "en")
  }
}
